#!/usr/bin/env node
// Regenerates the tokens consumed by:
//   - app/renderer.js          via app/lib/tokens-window.js  (window.TT_TOKENS)
//   - docs/ui-kit/palette.js   via docs/ui-kit/tokens.mjs    (ESM export)
//   - docs/colors_and_type.css via a marker-bounded GENERATED PALETTE block
//
// Source of truth: app/lib/tokens.json. Edit that, then run this.
// All three outputs are deterministic from the JSON, so a CI run that
// regenerates and diffs will catch hand-edits to the generated files.

const fs   = require('fs');
const path = require('path');

const ROOT       = path.resolve(__dirname, '..');
const SRC        = path.join(ROOT, 'app', 'lib', 'tokens.json');
const OUT_WIN_JS = path.join(ROOT, 'app', 'lib', 'tokens-window.js');
const OUT_KIT    = path.join(ROOT, 'docs', 'ui-kit', 'tokens.mjs');
const OUT_CSS    = path.join(ROOT, 'docs', 'colors_and_type.css');

const BEGIN = '/* === BEGIN GENERATED PALETTE — do not edit (run scripts/generate-tokens-css.cjs) === */';
const END   = '/* === END GENERATED PALETTE === */';

const tokens  = JSON.parse(fs.readFileSync(SRC, 'utf8'));
const palette = tokens.palette;

// --- output 1: window-global for the Electron renderer (no module system).
const winJs =
`// GENERATED by scripts/generate-tokens-css.cjs from app/lib/tokens.json.
// Do not hand-edit. Loaded by app/index.html before renderer.js.
window.TT_TOKENS = Object.freeze(${JSON.stringify(tokens, null, 2)});
`;
fs.writeFileSync(OUT_WIN_JS, winJs);

// --- output 2: ESM for the docs/ui-kit React demo.
const kit =
`// GENERATED by scripts/generate-tokens-css.cjs from app/lib/tokens.json.
// Do not hand-edit. Imported by docs/ui-kit/palette.js.
export const TOKENS = Object.freeze(${JSON.stringify(tokens, null, 2)});
export const PALETTE = TOKENS.palette;
`;
fs.writeFileSync(OUT_KIT, kit);

// --- output 3: palette block inside docs/colors_and_type.css.
//   - 8 base colour vars   (--tt-palette-base-NN)
//   - 24 arrangement vars  (--tt-palette-NN-bg) as ready-to-use background values
function arrangementBg(i) {
  const { BASE_COLOURS, HSPLIT_PARTNER, VSPLIT_PARTNER } = palette;
  if (i < 8)  return BASE_COLOURS[i];
  if (i < 16) {
    const p = i - 8;
    return `linear-gradient(to bottom, ${BASE_COLOURS[p]} 50%, ${BASE_COLOURS[HSPLIT_PARTNER[p]]} 50%)`;
  }
  const p = i - 16;
  return `linear-gradient(to right, ${BASE_COLOURS[p]} 50%, ${BASE_COLOURS[VSPLIT_PARTNER[p]]} 50%)`;
}

const baseLines = palette.BASE_COLOURS
  .map((hex, i) => `  --tt-palette-base-${String(i).padStart(2, '0')}: ${hex};   /* ${palette.COLOUR_NAMES[i]} */`)
  .join('\n');

const arrangementLines = Array.from({ length: palette.PALETTE_SIZE }, (_, i) =>
  `  --tt-palette-${String(i).padStart(2, '0')}-bg: ${arrangementBg(i)};`,
).join('\n');

const generatedBlock =
`${BEGIN}
:root {
${baseLines}

  --tt-palette-neutral: ${palette.NEUTRAL_COLOUR};

${arrangementLines}
}
${END}`;

let css;
try { css = fs.readFileSync(OUT_CSS, 'utf8'); }
catch { css = ''; }

if (css.includes(BEGIN) && css.includes(END)) {
  // Replace existing generated block in-place.
  const before = css.split(BEGIN)[0];
  const after  = css.split(END)[1] ?? '';
  css = before + generatedBlock + after;
} else {
  // First run: append a newline-padded block at the end of the file.
  const trimmed = css.replace(/\s+$/, '');
  css = `${trimmed}\n\n${generatedBlock}\n`;
}
fs.writeFileSync(OUT_CSS, css);

console.log(`tokens generated:
  ${path.relative(ROOT, OUT_WIN_JS)}
  ${path.relative(ROOT, OUT_KIT)}
  ${path.relative(ROOT, OUT_CSS)}  (palette block)`);
